startActivity(intent)

// Read the extras in DetailActivity.onCreate
val userId   = intent.getIntExtra("userId", -1)
val userName = intent.getStringExtra("userName") ?: "unknown"

// Open a URL — any browser can handle this
val url = Intent(Intent.ACTION_VIEW, Uri.parse("https://developer.android.com"))
startActivity(url)

// Share text — chooser lets user pick WhatsApp, Gmail, etc.
val share = Intent(Intent.ACTION_SEND).apply {
  type = "text/plain"
  putExtra(Intent.EXTRA_TEXT, "Check this out!")
}
startActivity(Intent.createChooser(share, "Share via"))

// Dial a number
startActivity(Intent(Intent.ACTION_DIAL, Uri.parse("tel:5551234")))

// SAFETY: always check that at least one app handles the intent
if (share.resolveActivity(packageManager) != null) {
  startActivity(share)
} else {
  Toast.makeText(this, "No app can handle this", Toast.LENGTH_SHORT).show()
}

