import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.widget.Button
import android.widget.LinearLayout
import android.widget.TextView
import androidx.activity.result.contract.ActivityResultContracts
import androidx.appcompat.app.AppCompatActivity

class MainActivity : AppCompatActivity() {

  // 1. Register a launcher for PickContent, get back a Uri or null
  private val pickImage =
    registerForActivityResult(ActivityResultContracts.GetContent()) { uri: Uri? ->
      uri?.let { display("picked: $it") }
    }

  // 2. Register a custom-activity launcher — DetailActivity returns a message
  private val detailLauncher =
    registerForActivityResult(ActivityResultContracts.StartActivityForResult()) { result ->
      if (result.resultCode == RESULT_OK) {
        val msg = result.data?.getStringExtra("reply") ?: "(no reply)"
        display("detail reply: $msg")
      }
    }

  private lateinit var status: TextView

  override fun onCreate(savedInstanceState: Bundle?) {
    super.onCreate(savedInstanceState)
    val layout = LinearLayout(this).apply { orientation = LinearLayout.VERTICAL }
    setContentView(layout)
    status = TextView(this).also(layout::addView)

    // (a) Explicit intent — go to DetailActivity, pass an extra
    layout.addView(Button(this).apply {
      text = "Open Detail"
      setOnClickListener {
        detailLauncher.launch(
          Intent(context, DetailActivity::class.java).putExtra("userId", 42)
        )
      }
    })

    // (b) Implicit intent — open a URL
    layout.addView(Button(this).apply {
      text = "Open Web"
      setOnClickListener {
        val i = Intent(Intent.ACTION_VIEW, Uri.parse("https://developer.android.com"))
        if (i.resolveActivity(packageManager) != null) startActivity(i)
        else display("no browser installed")
      }
    })

    // (c) Implicit intent — image picker
    layout.addView(Button(this).apply {
      text = "Pick Image"
      setOnClickListener { pickImage.launch("image/*") }
    })
  }

  private fun display(msg: String) { status.text = "$msg\n${status.text}" }
}

