class DetailActivity : AppCompatActivity() {
  override fun onCreate(savedInstanceState: Bundle?) {
    super.onCreate(savedInstanceState)
    val userId = intent.getIntExtra("userId", -1)

    Button(this).apply {
      text = "Reply and close (userId=$userId)"
      setOnClickListener {
        setResult(RESULT_OK, Intent().putExtra("reply", "greetings from userId=$userId"))
        finish()
      }
    }.also(::setContentView)
  }
}
